use std::panic;

/// Execute a tool with panic recovery.
/// Returns Ok(result) on success, Err(panic_message) on panic.
async fn execute_tool_with_panic_catch<F, Fut, R>(
    tool_name: &str,
    f: F,
) -> Result<R, String>
where
    F: FnOnce() -> Fut,
    Fut: std::future::Future<Output = R>,
{
    // Spawn the async task
    let handle = tokio::spawn(async move {
        f().await
    });

    // Await with panic catch
    match handle.await {
        Ok(result) => Ok(result),
        Err(join_err) => {
            if join_err.is_panic() {
                let panic_msg = if let Some(s) = join_err.into_panic().downcast_ref::<&str>() {
                    s.to_string()
                } else if let Some(s) = join_err.into_panic().downcast_ref::<String>() {
                    s.clone()
                } else {
                    "Unknown panic".to_string()
                };
                Err(format!("Tool '{}' panicked: {}", tool_name, panic_msg))
            } else {
                Err(format!("Task '{}' cancelled", tool_name))
            }
        }
    }
}
